/**
 * @summary Search airports by name or code
 */
export const getSearchAirportsUrl = (params: SearchAirportsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/airports?${stringifiedParams}`
    : `/api/airports`;
};

export const searchAirports = async (
  params: SearchAirportsParams,
  options?: RequestInit,
): Promise<Airport[]> => {
  return customFetch<Airport[]>(getSearchAirportsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchAirportsQueryKey = (params?: SearchAirportsParams) => {
  return [`/api/airports`, ...(params ? [params] : [])] as const;
};

export const getSearchAirportsQueryOptions = <
  TData = Awaited<ReturnType<typeof searchAirports>>,
  TError = ErrorType<unknown>,
>(
  params: SearchAirportsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchAirports>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getSearchAirportsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof searchAirports>>> = ({
    signal,
  }) => searchAirports(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof searchAirports>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type SearchAirportsQueryResult = NonNullable<
  Awaited<ReturnType<typeof searchAirports>>
>;
export type SearchAirportsQueryError = ErrorType<unknown>;

/**
 * @summary Search airports by name or code
 */

export function useSearchAirports<
  TData = Awaited<ReturnType<typeof searchAirports>>,
  TError = ErrorType<unknown>,
>(
  params: SearchAirportsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchAirports>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getSearchAirportsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
